<?php namespace App\Domains\Construction\Http\Controllers; use Illuminate\Http\Request; use App\Domains\Construction\Models\Project; class ProjectController { public function index() { return response()->json(Project::all()); } public function store(Request $request) { $project = Project::create($request->all()); return response()->json($project, 201); } public function show(Project $project) { return response()->json($project); } public function update(Request $request, Project $project) { $project->update($request->all()); return response()->json($project); } public function destroy(Project $project) { $project->delete(); return response()->json(null, 204); } }
